function interval = mainPresentMonoStimulus(ISI,nFrames,...		reconstructImage,SourceImage)    %function interval = mainPresentMonoStimulus(ISI,nFrames,...% 		bgClutT,testClut,reconstructImage,SourceImage,expType,...% 	targetClut)% Present a trial in the Simon experiment.%% 12/16/94	dhb, ccc	Wrote it.% 12/19/94	dhb, ccc	Rewrote.  ISI in milliseconds, play%											a tone.%  1/07/98  ccc         Convert to mono-screen setup% Declare screen globalsglobal screenRectT winT   % nBitsmidGray = [128 128 128] ;  % bgClutTSimg = double(SourceImage);nFrames = 30; %%%%%%%screenSize = get(0, 'ScreenSize');scrW = screenSize(3); % screenWidthscrH = screenSize(4); % screenHeightimgsz = 425;% pos_upperMiddle = [(scrW-imgsize)/2, (scrH-2*imgsize)/3, (scrW+imgsize)/2, (scrH+imgsize)/3];% pos_lowerLeft = [scrW/4-imgsize/2, (2*scrH-imgsize)/3, scrW/4+imgsize/2, (scrH+imgsize)*2/3 ];% pos_lowerRight = [scrW*(3/4)-imgsize/2, (2*scrH-imgsize)/3, scrW*(3/4)+imgsize/2, (scrH+imgsize)*2/3];% images closerpos_upperMiddle = [(scrW-imgsz)/2, (scrH-2*imgsz)/3, (scrW+imgsz)/2, (scrH+imgsz)/3];pos_lowerLeft = [scrW*(1/2)-imgsz*(6/5), (2*scrH-imgsz)/3, scrW*(1/2)-imgsz*(1/5), (scrH+imgsz)*2/3 ];pos_lowerRight = [scrW*(1/2)+imgsz*(1/5), (2*scrH-imgsz)/3, scrW*(1/2)+imgsz*(6/5), (scrH+imgsz)*2/3];% Decide interval orderinterval = CoinFlip(1,0.5) + 1;% igSize=2;BlankTime = 0.25; % Time for the blank screen in seconds% Target CLUT for whole damn trialif (interval == 1)    image2 = double(reconstructImage);    image1 = double(SourceImage);else    image1 = double(reconstructImage);    image2 = double(SourceImage);end% Now show the trial as a movie% First interval%PlayBeep(1000,100);Snd('Play',sin((0:4000)*0.2));        % Now show the trial as a movieScreen('WaitBlanking',winT);%==========================> change to the correct stimuli presentation% Display the first set of stimuli (300ms)fixRect = [0 0 3 3];fixRect = CenterRect(fixRect,screenRectT);Screen('FillOval',winT, 0,fixRect);Screen('FillRect', winT, midGray);Screen('PutImage', winT, Simg, pos_upperMiddle); % upperMiddleRectScreen('PutImage', winT, image1, pos_lowerLeft);% lowerLeftRectScreen('PutImage', winT, image2, pos_lowerRight);% lowerRightRectScreen('Flip', winT);PresentTime = nFrames/60;ts=GetSecs;% j=1;% Screen('LoadClut',winT,testClut(:,(j-1)*3+1:j*3),0,nBits);% % Screen('Flip',winT);while(GetSecs-ts<PresentTime)end% !!! show image in sequel !!!% % shuffle the order% if CoinFlip(1,0.5) == 1%     Screen('PutImage', winT, Simg, posleft);%     Screen('PutImage', winT, image1, posright);% 1st img% else%     Screen('PutImage', winT, image1, posleft);%     Screen('PutImage', winT, Simg, posright);% 1st img% end% Screen('Flip', winT);% ts = GetSecs;% while(GetSecs - ts < 0.3)% end% Blank screen (250ms) (or mask)Screen('FillRect', winT, midGray);Screen('FillOval',winT, 0,fixRect);% bgClutTScreen('Flip', winT);ts = GetSecs;while(GetSecs - ts < BlankTime)end% 2nd img% if CoinFlip(1,0.5) == 1%     Screen('PutImage', winT, Simg, posleft);%     Screen('PutImage', winT, image2, posright);% 1st img% else%     Screen('PutImage', winT, image2, posleft);%     Screen('PutImage', winT, Simg, posright);% 1st img% end% Screen('Flip', winT);% ts = GetSecs;% while(GetSecs - ts < 0.3)% end% % t0=GetSecs;% % Display the second set of stimuli (500ms)% Screen('FillOval',winT, 0,fixRect);% Screen('LoadClut',winT,midGray,0,nBits);% Screen('Flip',winT);% % Screen('WaitBlanking',winT);% % Screen('FillRect', winT, midGray); % Clear upper part bgClutT% Screen('PutImage', winT, image1, pos_lowerLeft);% Screen('PutImage', winT, image2, pos_lowerLeft);% % WaitSecs((ISI-(GetSecs-t0))/1000);% Snd('Play',sin((0:4000)*0.2));% ts=GetSecs;% % j=1;% % Screen('LoadClut',winT,testClut(:,(j-1)*3+1:j*3),0,nBits);% Screen('Flip',winT);% % while(GetSecs-ts<PresentTime)% end	% % Screen('Flip', winT);% <============================Screen('FillOval',winT, 0,fixRect);Screen('FillRect', winT, midGray);  % Screen('LoadClut',winT,bgClutT,0,nBits);Screen('Flip',winT);%Screen(winM,'SetClut',bgClutT,0,nBits);Screen('WaitBlanking',winT);